import { Link } from 'react-router-dom';
import T from '../tokens';

/**
 * EmptyState — Styled empty state with icon, message, and optional call-to-action.
 *
 * Props:
 *   icon      — SVG element or emoji string (default: package icon)
 *   title     — Heading text
 *   message   — Description text
 *   ctaLabel  — Call-to-action button text
 *   ctaTo     — Link destination for the CTA
 *   onCta     — onClick handler (alternative to ctaTo)
 */
export default function EmptyState({ icon, title, message, ctaLabel, ctaTo, onCta }) {
  const defaultIcon = (
    <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" style={{ opacity: 0.35 }}>
      <path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z" />
      <polyline points="3.27 6.96 12 12.01 20.73 6.96" />
      <line x1="12" y1="22.08" x2="12" y2="12" />
    </svg>
  );

  const renderedIcon = typeof icon === 'string'
    ? <div style={{ fontSize: 42, marginBottom: 12, opacity: 0.3 }}>{icon}</div>
    : <div style={{ marginBottom: 16, color: T.textSecondary }}>{icon || defaultIcon}</div>;

  return (
    <div style={{
      padding: '56px 32px',
      textAlign: 'center',
      borderRadius: 14,
      background: T.surface,
      border: `1px solid ${T.border}`,
    }}>
      {renderedIcon}
      {title && (
        <div style={{
          fontSize: 16, fontWeight: 700, color: T.textPrimary, marginBottom: 8,
          fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
        }}>
          {title}
        </div>
      )}
      {message && (
        <div style={{
          fontSize: 13, color: T.textSecondary, lineHeight: 1.6, maxWidth: 420,
          margin: '0 auto', fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
        }}>
          {message}
        </div>
      )}
      {ctaLabel && (ctaTo || onCta) && (
        <div style={{ marginTop: 20 }}>
          {ctaTo ? (
            <Link
              to={ctaTo}
              style={{
                display: 'inline-block',
                padding: '10px 24px',
                borderRadius: 10,
                background: 'linear-gradient(135deg, #60A5FA, #A78BFA)',
                color: '#fff',
                fontSize: 13,
                fontWeight: 600,
                textDecoration: 'none',
                fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
                boxShadow: '0 4px 16px rgba(96, 165, 250, 0.25)',
                transition: 'opacity 0.15s, transform 0.15s',
                minHeight: 44,
                lineHeight: '24px',
              }}
            >
              {ctaLabel}
            </Link>
          ) : (
            <button
              onClick={onCta}
              style={{
                padding: '10px 24px',
                borderRadius: 10,
                background: 'linear-gradient(135deg, #60A5FA, #A78BFA)',
                color: '#fff',
                fontSize: 13,
                fontWeight: 600,
                border: 'none',
                cursor: 'pointer',
                fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
                boxShadow: '0 4px 16px rgba(96, 165, 250, 0.25)',
                transition: 'opacity 0.15s, transform 0.15s',
                minHeight: 44,
              }}
            >
              {ctaLabel}
            </button>
          )}
        </div>
      )}
    </div>
  );
}

